import{_ as e,o as a,c as t,ai as r}from"./chunks/framework.CaiDwmc7.js";const b=JSON.parse('{"title":"大语言模型项目","description":"","frontmatter":{},"headers":[],"relativePath":"open-source/llm-projects.md","filePath":"open-source/llm-projects.md"}'),i={name:"open-source/llm-projects.md"};function o(n,l,h,s,u,g){return a(),t("div",null,[...l[0]||(l[0]=[r('<h1 id="大语言模型项目" tabindex="-1">大语言模型项目 <a class="header-anchor" href="#大语言模型项目" aria-label="Permalink to “大语言模型项目”">​</a></h1><p>本页面精选了大语言模型(LLM)相关的开源项目，包括模型、工具、应用框架等。</p><h2 id="开源大语言模型" tabindex="-1">开源大语言模型 <a class="header-anchor" href="#开源大语言模型" aria-label="Permalink to “开源大语言模型”">​</a></h2><h3 id="基础模型" tabindex="-1">基础模型 <a class="header-anchor" href="#基础模型" aria-label="Permalink to “基础模型”">​</a></h3><ul><li><p><strong>Llama</strong>：Meta开源大语言模型系列</p><ul><li>GitHub: <a href="https://github.com/facebookresearch/llama" target="_blank" rel="noreferrer">https://github.com/facebookresearch/llama</a></li><li>特点: 指令微调、多任务学习</li><li>版本: Llama 2, Llama 3</li></ul></li><li><p><strong>GPT-J</strong>：EleutherAI开源GPT模型</p><ul><li>GitHub: <a href="https://github.com/kingoflolz/mesh-transformer-jax" target="_blank" rel="noreferrer">https://github.com/kingoflolz/mesh-transformer-jax</a></li><li>特点: 6B参数、开源替代</li></ul></li><li><p><strong>BLOOM</strong>：BigScience多语言大模型</p><ul><li>GitHub: <a href="https://github.com/bigscience-workshop/bloom" target="_blank" rel="noreferrer">https://github.com/bigscience-workshop/bloom</a></li><li>特点: 176种语言、分布式训练</li></ul></li><li><p><strong>Falcon</strong>：TII开源大模型</p><ul><li>GitHub: <a href="https://github.com/tiiuae/falcon" target="_blank" rel="noreferrer">https://github.com/tiiuae/falcon</a></li><li>特点: 高性能、商业友好许可</li></ul></li></ul><h3 id="中文模型" tabindex="-1">中文模型 <a class="header-anchor" href="#中文模型" aria-label="Permalink to “中文模型”">​</a></h3><ul><li><p><strong>ChatGLM</strong>：智谱AI对话模型</p><ul><li>GitHub: <a href="https://github.com/THUDM/ChatGLM-6B" target="_blank" rel="noreferrer">https://github.com/THUDM/ChatGLM-6B</a></li><li>特点: 中文优化、轻量级</li></ul></li><li><p><strong>Baichuan</strong>：百川智能大模型</p><ul><li>GitHub: <a href="https://github.com/baichuan-inc/Baichuan-7B" target="_blank" rel="noreferrer">https://github.com/baichuan-inc/Baichuan-7B</a></li><li>特点: 商业级、开源可用</li></ul></li><li><p><strong>Qwen</strong>：阿里通义千问</p><ul><li>GitHub: <a href="https://github.com/QwenLM/Qwen" target="_blank" rel="noreferrer">https://github.com/QwenLM/Qwen</a></li><li>特点: 多语言、工具调用</li></ul></li></ul><h3 id="代码模型" tabindex="-1">代码模型 <a class="header-anchor" href="#代码模型" aria-label="Permalink to “代码模型”">​</a></h3><ul><li><p><strong>Code Llama</strong>：Meta代码生成模型</p><ul><li>GitHub: <a href="https://github.com/facebookresearch/codellama" target="_blank" rel="noreferrer">https://github.com/facebookresearch/codellama</a></li><li>功能: 代码生成、解释、调试</li></ul></li><li><p><strong>StarCoder</strong>：BigCode代码模型</p><ul><li>GitHub: <a href="https://github.com/bigcode-project/starcoder" target="_blank" rel="noreferrer">https://github.com/bigcode-project/starcoder</a></li><li>特点: 多语言代码、80+编程语言</li></ul></li></ul><h2 id="模型平台与工具" tabindex="-1">模型平台与工具 <a class="header-anchor" href="#模型平台与工具" aria-label="Permalink to “模型平台与工具”">​</a></h2><h3 id="hugging-face-生态" tabindex="-1">Hugging Face 生态 <a class="header-anchor" href="#hugging-face-生态" aria-label="Permalink to “Hugging Face 生态”">​</a></h3><ul><li><p><strong>Transformers</strong>：模型库和工具</p><ul><li>GitHub: <a href="https://github.com/huggingface/transformers" target="_blank" rel="noreferrer">https://github.com/huggingface/transformers</a></li><li>功能: 60,000+预训练模型</li></ul></li><li><p><strong>Datasets</strong>：数据集处理库</p><ul><li>GitHub: <a href="https://github.com/huggingface/datasets" target="_blank" rel="noreferrer">https://github.com/huggingface/datasets</a></li><li>功能: 数据加载、处理</li></ul></li><li><p><strong>Accelerate</strong>：分布式训练库</p><ul><li>GitHub: <a href="https://github.com/huggingface/accelerate" target="_blank" rel="noreferrer">https://github.com/huggingface/accelerate</a></li><li>功能: 简化分布式训练</li></ul></li></ul><h3 id="modelscope" tabindex="-1">ModelScope <a class="header-anchor" href="#modelscope" aria-label="Permalink to “ModelScope”">​</a></h3><ul><li><p><strong>ModelScope</strong>：阿里模型平台</p><ul><li>GitHub: <a href="https://github.com/modelscope/modelscope" target="_blank" rel="noreferrer">https://github.com/modelscope/modelscope</a></li><li>功能: 中文模型、工具链</li></ul></li><li><p><strong>Swift</strong>：ModelScope微调工具</p><ul><li>GitHub: <a href="https://github.com/modelscope/swift" target="_blank" rel="noreferrer">https://github.com/modelscope/swift</a></li><li>功能: 高效微调、量化</li></ul></li></ul><h2 id="llm应用框架" tabindex="-1">LLM应用框架 <a class="header-anchor" href="#llm应用框架" aria-label="Permalink to “LLM应用框架”">​</a></h2><h3 id="langchain-生态" tabindex="-1">LangChain 生态 <a class="header-anchor" href="#langchain-生态" aria-label="Permalink to “LangChain 生态”">​</a></h3><ul><li><p><strong>LangChain</strong>：LLM应用开发框架</p><ul><li>GitHub: <a href="https://github.com/langchain-ai/langchain" target="_blank" rel="noreferrer">https://github.com/langchain-ai/langchain</a></li><li>功能: 链式调用、记忆、代理</li></ul></li><li><p><strong>LangChain.js</strong>：JavaScript版本</p><ul><li>GitHub: <a href="https://github.com/langchain-ai/langchainjs" target="_blank" rel="noreferrer">https://github.com/langchain-ai/langchainjs</a></li><li>功能: Node.js/Web LLM应用</li></ul></li><li><p><strong>LangServe</strong>：LangChain服务部署</p><ul><li>GitHub: <a href="https://github.com/langchain-ai/langserve" target="_blank" rel="noreferrer">https://github.com/langchain-ai/langserve</a></li><li>功能: API服务、流式响应</li></ul></li></ul><h3 id="llamaindex" tabindex="-1">LlamaIndex <a class="header-anchor" href="#llamaindex" aria-label="Permalink to “LlamaIndex”">​</a></h3><ul><li><p><strong>LlamaIndex</strong>：LLM数据框架</p><ul><li>GitHub: <a href="https://github.com/run-llama/llama_index" target="_blank" rel="noreferrer">https://github.com/run-llama/llama_index</a></li><li>功能: RAG、数据索引、检索</li></ul></li><li><p><strong>LlamaParse</strong>：文档解析工具</p><ul><li>GitHub: <a href="https://github.com/run-llama/llama_parse" target="_blank" rel="noreferrer">https://github.com/run-llama/llama_parse</a></li><li>功能: 复杂文档解析</li></ul></li></ul><h3 id="其他框架" tabindex="-1">其他框架 <a class="header-anchor" href="#其他框架" aria-label="Permalink to “其他框架”">​</a></h3><ul><li><p><strong>AutoGen</strong>：微软多代理框架</p><ul><li>GitHub: <a href="https://github.com/microsoft/autogen" target="_blank" rel="noreferrer">https://github.com/microsoft/autogen</a></li><li>功能: 代理对话、任务解决</li></ul></li><li><p><strong>CrewAI</strong>：多代理协作框架</p><ul><li>GitHub: <a href="https://github.com/joaomdmoura/crewai" target="_blank" rel="noreferrer">https://github.com/joaomdmoura/crewai</a></li><li>功能: 角色扮演、任务分配</li></ul></li></ul><h2 id="微调与训练工具" tabindex="-1">微调与训练工具 <a class="header-anchor" href="#微调与训练工具" aria-label="Permalink to “微调与训练工具”">​</a></h2><h3 id="微调框架" tabindex="-1">微调框架 <a class="header-anchor" href="#微调框架" aria-label="Permalink to “微调框架”">​</a></h3><ul><li><p><strong>PEFT</strong>：参数高效微调</p><ul><li>GitHub: <a href="https://github.com/huggingface/peft" target="_blank" rel="noreferrer">https://github.com/huggingface/peft</a></li><li>功能: LoRA、Prefix Tuning</li></ul></li><li><p><strong>Axolotl</strong>：LLM微调工具</p><ul><li>GitHub: <a href="https://github.com/OpenAccess-AI-Collective/axolotl" target="_blank" rel="noreferrer">https://github.com/OpenAccess-AI-Collective/axolotl</a></li><li>功能: 多种微调方法</li></ul></li></ul><h3 id="训练优化" tabindex="-1">训练优化 <a class="header-anchor" href="#训练优化" aria-label="Permalink to “训练优化”">​</a></h3><ul><li><p><strong>DeepSpeed</strong>：微软深度学习优化库</p><ul><li>GitHub: <a href="https://github.com/microsoft/DeepSpeed" target="_blank" rel="noreferrer">https://github.com/microsoft/DeepSpeed</a></li><li>功能: 大模型训练优化</li></ul></li><li><p><strong>Megatron-LM</strong>：NVIDIA大模型训练</p><ul><li>GitHub: <a href="https://github.com/NVIDIA/Megatron-LM" target="_blank" rel="noreferrer">https://github.com/NVIDIA/Megatron-LM</a></li><li>功能: 分布式训练</li></ul></li></ul><h2 id="模型量化与压缩" tabindex="-1">模型量化与压缩 <a class="header-anchor" href="#模型量化与压缩" aria-label="Permalink to “模型量化与压缩”">​</a></h2><ul><li><p><strong>GPTQ</strong>：模型量化</p><ul><li>GitHub: <a href="https://github.com/IST-DASLab/gptq" target="_blank" rel="noreferrer">https://github.com/IST-DASLab/gptq</a></li><li>功能: 4-bit量化、推理加速</li></ul></li><li><p><strong>AWQ</strong>：激活感知量化</p><ul><li>GitHub: <a href="https://github.com/mit-han-lab/llm-awq" target="_blank" rel="noreferrer">https://github.com/mit-han-lab/llm-awq</a></li><li>功能: 高精度量化</li></ul></li><li><p><strong>AutoGPTQ</strong>：自动量化工具</p><ul><li>GitHub: <a href="https://github.com/PanQiWei/AutoGPTQ" target="_blank" rel="noreferrer">https://github.com/PanQiWei/AutoGPTQ</a></li><li>功能: 一键量化</li></ul></li></ul><h2 id="推理与部署" tabindex="-1">推理与部署 <a class="header-anchor" href="#推理与部署" aria-label="Permalink to “推理与部署”">​</a></h2><h3 id="推理引擎" tabindex="-1">推理引擎 <a class="header-anchor" href="#推理引擎" aria-label="Permalink to “推理引擎”">​</a></h3><ul><li><p><strong>vLLM</strong>：高性能LLM推理</p><ul><li>GitHub: <a href="https://github.com/vllm-project/vllm" target="_blank" rel="noreferrer">https://github.com/vllm-project/vllm</a></li><li>功能: 连续批处理、PagedAttention</li></ul></li><li><p><strong>TGI (Text Generation Inference)</strong>：Hugging Face推理服务</p><ul><li>GitHub: <a href="https://github.com/huggingface/text-generation-inference" target="_blank" rel="noreferrer">https://github.com/huggingface/text-generation-inference</a></li><li>功能: 优化的推理服务</li></ul></li><li><p><strong>Ollama</strong>：本地LLM运行</p><ul><li>GitHub: <a href="https://github.com/jmorganca/ollama" target="_blank" rel="noreferrer">https://github.com/jmorganca/ollama</a></li><li>功能: 本地模型管理</li></ul></li></ul><h3 id="部署工具" tabindex="-1">部署工具 <a class="header-anchor" href="#部署工具" aria-label="Permalink to “部署工具”">​</a></h3><ul><li><p><strong>LMDeploy</strong>：LLM部署工具</p><ul><li>GitHub: <a href="https://github.com/InternLM/lmdeploy" target="_blank" rel="noreferrer">https://github.com/InternLM/lmdeploy</a></li><li>功能: 量化部署、推理加速</li></ul></li><li><p><strong>TensorRT-LLM</strong>：NVIDIA推理优化</p><ul><li>GitHub: <a href="https://github.com/NVIDIA/TensorRT-LLM" target="_blank" rel="noreferrer">https://github.com/NVIDIA/TensorRT-LLM</a></li><li>功能: GPU推理优化</li></ul></li></ul><h2 id="评估与基准测试" tabindex="-1">评估与基准测试 <a class="header-anchor" href="#评估与基准测试" aria-label="Permalink to “评估与基准测试”">​</a></h2><ul><li><p><strong>Open LLM Leaderboard</strong>：模型评估平台</p><ul><li>GitHub: <a href="https://github.com/open-llm-leaderboard/open-llm-leaderboard" target="_blank" rel="noreferrer">https://github.com/open-llm-leaderboard/open-llm-leaderboard</a></li><li>功能: 自动化评估</li></ul></li><li><p><strong>LM Evaluation Harness</strong>：EleutherAI评估工具</p><ul><li>GitHub: <a href="https://github.com/EleutherAI/lm-evaluation-harness" target="_blank" rel="noreferrer">https://github.com/EleutherAI/lm-evaluation-harness</a></li><li>功能: 标准基准测试</li></ul></li></ul><h2 id="应用与demo" tabindex="-1">应用与Demo <a class="header-anchor" href="#应用与demo" aria-label="Permalink to “应用与Demo”">​</a></h2><h3 id="聊天界面" tabindex="-1">聊天界面 <a class="header-anchor" href="#聊天界面" aria-label="Permalink to “聊天界面”">​</a></h3><ul><li><p><strong>Chatbot UI</strong>：开源聊天界面</p><ul><li>GitHub: <a href="https://github.com/mckaywrigley/chatbot-ui" target="_blank" rel="noreferrer">https://github.com/mckaywrigley/chatbot-ui</a></li><li>功能: 美观界面、多模型支持</li></ul></li><li><p><strong>PrivateGPT</strong>：本地文档问答</p><ul><li>GitHub: <a href="https://github.com/imartinez/privateGPT" target="_blank" rel="noreferrer">https://github.com/imartinez/privateGPT</a></li><li>功能: 隐私保护、离线使用</li></ul></li></ul><h3 id="开发工具" tabindex="-1">开发工具 <a class="header-anchor" href="#开发工具" aria-label="Permalink to “开发工具”">​</a></h3><ul><li><p><strong>Continue</strong>：VS Code AI编程助手</p><ul><li>GitHub: <a href="https://github.com/continuedev/continue" target="_blank" rel="noreferrer">https://github.com/continuedev/continue</a></li><li>功能: 代码生成、解释</li></ul></li><li><p><strong>GitHub Copilot Alternative</strong>：开源代码助手</p><ul><li>GitHub: <a href="https://github.com/BloopAI/bloop" target="_blank" rel="noreferrer">https://github.com/BloopAI/bloop</a></li><li>功能: 本地代码搜索</li></ul></li></ul><h2 id="数据集与资源" tabindex="-1">数据集与资源 <a class="header-anchor" href="#数据集与资源" aria-label="Permalink to “数据集与资源”">​</a></h2><ul><li><p><strong>OpenWebText</strong>：开源文本数据集</p><ul><li>GitHub: <a href="https://github.com/jcpeterson/openwebtext" target="_blank" rel="noreferrer">https://github.com/jcpeterson/openwebtext</a></li><li>功能: 训练数据</li></ul></li><li><p><strong>C4</strong>：Common Crawl数据集</p><ul><li>GitHub: <a href="https://github.com/google-research-datasets/c4" target="_blank" rel="noreferrer">https://github.com/google-research-datasets/c4</a></li><li>功能: 大规模文本数据</li></ul></li></ul><h2 id="安全与对齐" tabindex="-1">安全与对齐 <a class="header-anchor" href="#安全与对齐" aria-label="Permalink to “安全与对齐”">​</a></h2><ul><li><p><strong>OpenAI Moderation</strong>：内容审核</p><ul><li>GitHub: <a href="https://github.com/openai/moderation-api" target="_blank" rel="noreferrer">https://github.com/openai/moderation-api</a></li><li>功能: 安全过滤</li></ul></li><li><p><strong>Constitutional AI</strong>：Anthropic对齐方法</p><ul><li>GitHub: <a href="https://github.com/anthropics/constitutional-ai" target="_blank" rel="noreferrer">https://github.com/anthropics/constitutional-ai</a></li><li>功能: AI安全对齐</li></ul></li></ul>',44)])])}const p=e(i,[["render",o]]);export{b as __pageData,p as default};
